const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let pos=0;
const T=Number(input[pos++]);
let res=[];
for(let i=0;i<T;i++){
  let N=Number(input[pos++]);
  if(N===0){res.push('0');continue;}
  let bits='';
  while(N>0){bits=(N&1)+bits;N>>=1;}
  res.push(bits);
}
console.log(res.join('\n'));
